@startchen
entity APPLICATION {
  ApplicationId <<key>>
}

entity MODULE {
  ModuleId <<key>>
}

entity ACCOUNT_SUMMARY {
  AccountSummaryId <<key>>
}

relationship GENERATE_ACCOUNT_SUMMARIES {
}

relationship CONTAIN_MODULE {
}

CONTAIN_MODULE =1= APPLICATION
CONTAIN_MODULE -N- MODULE

GENERATE_ACCOUNT_SUMMARIES =1= MODULE
GENERATE_ACCOUNT_SUMMARIES -N- ACCOUNT_SUMMARY
@endchen

